+
+        let label = format!("{pct:.1}%");
+        let mut cell = Cell::new(label).set_alignment(CellAlignment::Right);
+
+        if self.colors_enabled {
+            // Color based on noise level: high noise = yellow/red warning
+            cell = if pct > 50.0 {
+                cell.fg(Color::Red)
+            } else if pct > 25.0 {
+                cell.fg(Color::Yellow)
+            } else {
+                cell.fg(Color::Green)
+            };
+        }
+
+        cell
+    }
+}
